args.ReplacementContent:
"      {/* Backdrop overlay for mobile */}
      {isMobileSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-950/40 backdrop-blur-sm z-[90] lg:hidden"
          onClick={() => setIsMobileSidebarOpen(false)}
        />
      )}

      {/* Sidebar - MATCH CANDIDATE STYLE WITH RESPONSIVE BEHAVIOR */}
      <aside className={`w-64 bg-gradient-to-b from-primary-600 via-primary-700 to-highlight-700 p-6 flex flex-col fixed h-full z-[100] shadow-2xl transition-transform duration-300 ${
        isMobileSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'
      }`}>"

