      {/* Sidebar - MATCH CANDIDATE STYLE WITH RESPONSIVE BEHAVIOR */}
      <aside className={`w-64 bg-gradient-to-b from-primary-600 via-primary-700 to-highlight-700 p-6 flex flex-col fixed h-full z-50 shadow-2xl transition-transform duration-300 ${
